package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithEscape() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Define the escape character
        char escape = '\\';

        // Mock the behavior of withEscape method
        when(csvFormat.withEscape(escape)).thenReturn(csvFormat);

        // Invoke the withEscape method using reflection
        try {
            CSVFormat result = (CSVFormat) csvFormat.getClass().getDeclaredMethod("withEscape", char.class)
                    .invoke(csvFormat, escape);

            // Assert the result
            assertEquals(csvFormat, result);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
